@page "/settings"
@using sv_fab198ddd96944b39450978258ec56d2.Services
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-container">
    <nav class="settings-sidebar">
        <h2 class="settings-title">Settings</h2>
        <ul class="settings-nav">
            @foreach (var section in _sections)
            {
                <li class="@(ActiveSection == section.Key ? "active" : "")" @onclick="() => ActiveSection = section.Key">
                    <span class="nav-icon">@section.Value.Icon</span>
                    <span>@section.Value.Label</span>
                </li>
            }
        </ul>
    </nav>

    <main class="settings-content">
        @if (_loading)
        {
            <div class="loading-spinner">Loading...</div>
        }
        else
        {
            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }

        @if (!string.IsNullOrEmpty(_toastMessage))
        {
            <div class="toast @_toastType">
                <span>@_toastMessage</span>
                <button class="toast-close" @onclick="DismissToast">✕</button>
            </div>
        }
    </main>
</div>

@code {
    private string ActiveSection { get; set; } = "profile";
    private bool _loading = true;

    // Toast
    private string _toastMessage = "";
    private string _toastType = "success";

    // Profile state
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private UserProfile? _savedProfile;

    // Notification state
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = new() { "general", "marketing", "engineering", "announcements", "random" };
    private HashSet<string> _mutedChannels = new();

    // Security state
    private SecuritySettings? _securitySettings;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _twoFactorEnabled;
    private string? _sessionToRevoke;
    private bool _showRevokeConfirm;

    // Appearance state
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private readonly List<string> _languages = new() { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🔒"),
        ["appearance"] = ("Appearance", "🎨")
    };

    protected override async Task OnInitializedAsync()
    {
        await LoadAllData();
        _loading = false;
    }

    private async Task LoadAllData()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);

        var notifs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = notifs.EmailNotifications;
        _pushNotifications = notifs.PushNotifications;
        _weeklyDigest = notifs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(notifs.MutedChannels);

        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _securitySettings.TwoFactorEnabled;

        var appearance = await SettingsService.GetAppearanceAsync();
        _theme = appearance.Theme;
        _fontSize = appearance.FontSize;
        _language = appearance.Language;
        _compactMode = appearance.CompactMode;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private void ShowToast(string message, string type = "success")
    {
        _toastMessage = message;
        _toastType = type;
        _ = DismissToastAfterDelay();
    }

    private async Task DismissToastAfterDelay()
    {
        await Task.Delay(3000);
        _toastMessage = "";
        await InvokeAsync(StateHasChanged);
    }

    private void DismissToast() => _toastMessage = "";

    // Profile methods
    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }

    // Notification methods
    private void ToggleMuteChannel(string channel, ChangeEventArgs e)
    {
        if (e.Value is bool muted && muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotificationPrefs()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        ShowToast("Notification preferences saved!");
    }

    // Security methods
    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", "error");
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New passwords do not match.", "error");
            return;
        }
        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changePasswordExpanded = false;
        _securitySettings = await SettingsService.GetSecuritySettingsAsync();
        ShowToast("Password updated successfully!");
    }

    private void PromptRevokeSession(string sessionId)
    {
        _sessionToRevoke = sessionId;
        _showRevokeConfirm = true;
    }

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            ShowToast("Session revoked.");
        }
        _showRevokeConfirm = false;
        _sessionToRevoke = null;
    }

    private void CancelRevoke()
    {
        _showRevokeConfirm = false;
        _sessionToRevoke = null;
    }

    // Appearance methods
    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        ShowToast("Appearance settings saved!");
    }

    // Render fragments
    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Profile</h3>

            <div class="avatar-area">
                <div class="avatar-preview">
                    <img src="@_avatarUrl" alt="Avatar" />
                </div>
                <div class="avatar-url">
                    <label>Avatar URL</label>
                    <input type="text" @bind="_avatarUrl" placeholder="https://..." />
                </div>
            </div>

            <div class="form-group">
                <label>Display Name</label>
                <input type="text" @bind="_displayName" />
            </div>

            <div class="form-group">
                <label>Email</label>
                <input type="email" @bind="_email" />
            </div>

            <div class="form-group">
                <label>Bio</label>
                <textarea rows="4" @bind="_bio"></textarea>
            </div>

            <div class="button-group">
                <button class="btn-primary" @onclick="SaveProfile">Save Changes</button>
                <button class="btn-secondary" @onclick="DiscardProfileChanges">Discard Changes</button>
            </div>
        </section>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Notifications</h3>

            <div class="toggle-group">
                <div class="toggle-item">
                    <label class="toggle-label">
                        <span>Email Notifications</span>
                        <label class="switch">
                            <input type="checkbox" @bind="_emailNotifications" />
                            <span class="slider"></span>
                        </label>
                    </label>
                </div>
                <div class="toggle-item">
                    <label class="toggle-label">
                        <span>Push Notifications</span>
                        <label class="switch">
                            <input type="checkbox" @bind="_pushNotifications" />
                            <span class="slider"></span>
                        </label>
                    </label>
                </div>
                <div class="toggle-item">
                    <label class="toggle-label">
                        <span>Weekly Digest</span>
                        <label class="switch">
                            <input type="checkbox" @bind="_weeklyDigest" />
                            <span class="slider"></span>
                        </label>
                    </label>
                </div>
            </div>

            <h4>Muted Channels</h4>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="(e) => ToggleMuteChannel(channel, e)" />
                        <span>#@channel</span>
                    </label>
                }
            </div>

            <div class="button-group">
                <button class="btn-primary" @onclick="SaveNotificationPrefs">Save Preferences</button>
            </div>
        </section>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h3>Security</h3>

            <div class="expandable-panel">
                <button class="panel-header" @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                    <span>Change Password</span>
                    <span class="expand-icon">@(_changePasswordExpanded ? "▾" : "▸")</span>
                </button>
                @if (_changePasswordExpanded)
                {
                    <div class="panel-body">
                        <div class="form-group">
                            <label>Current Password</label>
                            <input type="password" @bind="_currentPassword" />
                        </div>
                        <div class="form-group">
                            <label>New Password</label>
                            <input type="password" @bind="_newPassword" />
                        </div>
                        <div class="form-group">
                            <label>Confirm New Password</label>
                            <input type="password" @bind="_confirmPassword" />
                        </div>
                        <button class="btn-primary" @onclick="ChangePassword">Update Password</button>
                    </div>
                }
            </div>

            <div class="toggle-item" style="margin-top: 1.5rem;">
                <label class="toggle-label">
                    <span>
                        Two-Factor Authentication
                        <span class="status-badge @(_twoFactorEnabled ? "enabled" : "disabled")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </span>
                    <label class="switch">
                        <input type="checkbox" @bind="_twoFactorEnabled" />
                        <span class="slider"></span>
                    </label>
                </label>
            </div>

            @if (_securitySettings?.LastPasswordChange is not null)
            {
                <p class="info-text">Last password change: @_securitySettings.LastPasswordChange.Value.ToString("MMMM dd, yyyy")</p>
            }

            <h4>Active Sessions</h4>
            <div class="sessions-table-wrapper">
                <table class="sessions-table">
                    <thead>
                        <tr>
                            <th>Device</th>
                            <th>Location</th>
                            <th>Last Active</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        @if (_securitySettings?.Sessions is not null)
                        {
                            @foreach (var session in _securitySettings.Sessions)
                            {
                                <tr>
                                    <td>@session.Device</td>
                                    <td>@session.Location</td>
                                    <td>@session.LastActive.ToString("g")</td>
                                    <td>
                                        @if (session.Id != _securitySettings.Sessions.First().Id)
                                        {
                                            <button class="btn-danger btn-sm" @onclick="() => PromptRevokeSession(session.Id)">Revoke</button>
                                        }
                                        else
                                        {
                                            <span class="current-badge">Current</span>
                                        }
                                    </td>
                                </tr>
                            }
                        }
                    </tbody>
                </table>
            </div>

            @if (_showRevokeConfirm)
            {
                <div class="modal-overlay">
                    <div class="modal-dialog">
                        <h4>Confirm Session Revocation</h4>
                        <p>Are you sure you want to revoke this session? The device will be signed out immediately.</p>
                        <div class="button-group">
                            <button class="btn-danger" @onclick="ConfirmRevokeSession">Revoke Session</button>
                            <button class="btn-secondary" @onclick="CancelRevoke">Cancel</button>
                        </div>
                    </div>
                </div>
            }
        </section>
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Appearance</h3>

            <div class="form-group">
                <label>Theme</label>
                <div class="radio-group">
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <label class="radio-item">
                            <input type="radio" name="theme" value="@theme" checked="@(_theme == theme)" @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label>Font Size</label>
                <div class="radio-group">
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <label class="radio-item">
                            <input type="radio" name="fontSize" value="@size" checked="@(_fontSize == size)" @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label>Language</label>
                <select @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="toggle-item">
                <label class="toggle-label">
                    <span>Compact Mode</span>
                    <label class="switch">
                        <input type="checkbox" @bind="_compactMode" />
                        <span class="slider"></span>
                    </label>
                </label>
            </div>

            <h4>Preview</h4>
            <div class="appearance-preview @(_theme.ToLower()) @(_fontSize.ToLower()) @(_compactMode ? "compact" : "")">
                <div class="preview-header">Sample Header</div>
                <p class="preview-body">This is a preview of how your content will look with the selected appearance settings.</p>
                <button class="preview-button">Sample Button</button>
            </div>

            <div class="button-group">
                <button class="btn-primary" @onclick="SaveAppearance">Save</button>
            </div>
        </section>
    };
}

