arguments.file_text:
.settings-container {
    display: flex;
    min-height: calc(100vh - 4rem);
    max-width: 1200px;
    margin: 0 auto;
    gap: 2rem;
    padding: 2rem;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
}

.settings-title {
    font-size: 1.25rem;
    font-weight: 600;
    margin-bottom: 1rem;
    color: #1a1a2e;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav li {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1rem;
    border-radius: 8px;
    cursor: pointer;
    font-size: 0.95rem;
    color: #555;
    transition: all 0.2s ease;
}

.settings-nav li:hover {
    background: #f0f0f5;
    color: #1a1a2e;
}

.settings-nav li.active {
    background: #e8e0ff;
    color: #5b21b6;
    font-weight: 600;
}

.nav-icon {
    font-size: 1.1rem;
}

/* Main content */
.settings-content {
